"""sklearn.discriminant_analysis — LDA and QDA classifiers."""
import numpy as np
from sklearn.base import BaseEstimator, ClassifierMixin, TransformerMixin


class LinearDiscriminantAnalysis(BaseEstimator, ClassifierMixin, TransformerMixin):
    """Linear Discriminant Analysis classifier and dimensionality reducer.

    Parameters
    ----------
    n_components : int or None, default=None
    solver : str, default='svd'
    """

    def __init__(self, solver='svd', shrinkage=None, priors=None,
                 n_components=None, store_covariance=False, tol=1e-4,
                 covariance_estimator=None):
        self.solver = solver
        self.shrinkage = shrinkage
        self.priors = priors
        self.n_components = n_components
        self.store_covariance = store_covariance
        self.tol = tol
        self.covariance_estimator = covariance_estimator

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y)
        self.classes_ = np.unique(y)
        n_classes = len(self.classes_)
        n_features = X.shape[1]

        self.priors_ = np.array([np.mean(y == c) for c in self.classes_])
        self.means_ = np.array([X[y == c].mean(axis=0) for c in self.classes_])
        overall_mean = X.mean(axis=0)

        # Within-class scatter
        Sw = np.zeros((n_features, n_features))
        for c in self.classes_:
            Xc = X[y == c] - self.means_[list(self.classes_).index(c)]
            Sw += Xc.T @ Xc

        # Between-class scatter
        Sb = np.zeros((n_features, n_features))
        for i, c in enumerate(self.classes_):
            nc = np.sum(y == c)
            diff = (self.means_[i] - overall_mean).reshape(-1, 1)
            Sb += nc * diff @ diff.T

        # Solve eigenvalue problem
        Sw_reg = Sw + 1e-6 * np.eye(n_features)
        eig_vals, eig_vecs = np.linalg.eigh(np.linalg.pinv(Sw_reg) @ Sb)
        idx = np.argsort(eig_vals)[::-1]
        n_comp = self.n_components or min(n_classes - 1, n_features)
        self.scalings_ = eig_vecs[:, idx[:n_comp]].real
        self.coef_ = (np.linalg.pinv(Sw_reg) @ (self.means_[1] - self.means_[0]).T).T if n_classes == 2 else None
        self.intercept_ = np.zeros(1)
        return self

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        return X @ self.scalings_

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        # Project and find nearest class mean
        X_proj = self.transform(X)
        means_proj = self.means_ @ self.scalings_
        dists = np.array([np.sum((X_proj - m) ** 2, axis=1) for m in means_proj]).T
        return self.classes_[np.argmin(dists, axis=1)]

    def predict_proba(self, X):
        X = np.asarray(X, dtype=float)
        X_proj = self.transform(X)
        means_proj = self.means_ @ self.scalings_
        dists = np.array([np.sum((X_proj - m) ** 2, axis=1) for m in means_proj]).T
        log_probs = -0.5 * dists + np.log(self.priors_ + 1e-15)
        log_probs -= log_probs.max(axis=1, keepdims=True)
        probs = np.exp(log_probs)
        return probs / probs.sum(axis=1, keepdims=True)


class QuadraticDiscriminantAnalysis(BaseEstimator, ClassifierMixin):
    """Quadratic Discriminant Analysis classifier.

    Parameters
    ----------
    reg_param : float, default=0.0
    """

    def __init__(self, *, priors=None, reg_param=0.0,
                 store_covariance=False, tol=1e-4):
        self.priors = priors
        self.reg_param = reg_param
        self.store_covariance = store_covariance
        self.tol = tol

    def fit(self, X, y):
        X, y = np.asarray(X, dtype=float), np.asarray(y)
        self.classes_ = np.unique(y)
        self.priors_ = np.array([np.mean(y == c) for c in self.classes_])
        self.means_ = []
        self.covariances_ = []
        for c in self.classes_:
            Xc = X[y == c]
            mu = Xc.mean(axis=0)
            self.means_.append(mu)
            diff = Xc - mu
            cov = diff.T @ diff / len(Xc)
            cov += self.reg_param * np.eye(X.shape[1])
            self.covariances_.append(cov)
        self.means_ = np.array(self.means_)
        return self

    def predict(self, X):
        return self.classes_[np.argmax(self.predict_proba(X), axis=1)]

    def predict_proba(self, X):
        X = np.asarray(X, dtype=float)
        log_probs = []
        for i, c in enumerate(self.classes_):
            cov = self.covariances_[i]
            sign, logdet = np.linalg.slogdet(cov)
            prec = np.linalg.pinv(cov)
            diff = X - self.means_[i]
            maha = np.sum(diff @ prec * diff, axis=1)
            lp = -0.5 * (logdet + maha) + np.log(self.priors_[i] + 1e-15)
            log_probs.append(lp)
        log_probs = np.array(log_probs).T
        log_probs -= log_probs.max(axis=1, keepdims=True)
        probs = np.exp(log_probs)
        return probs / probs.sum(axis=1, keepdims=True)
